// Validacion HMAC timing-safe via XOR char-by-char (sandbox-safe).
// El secret esperado viene de env y se compara contra el header X-Internal-Secret.
const headers = $input.first().json.headers || {};
const received = headers['x-internal-secret'] || '';
const expected = $env.INTERNAL_WEBHOOK_SECRET || '';
if (!received || received.length !== expected.length) {
  throw new Error('Unauthorized: invalid internal secret');
}
let diff = 0;
for (let i = 0; i < expected.length; i++) {
  diff |= received.charCodeAt(i) ^ expected.charCodeAt(i);
}
if (diff !== 0) throw new Error('Unauthorized: invalid internal secret');

// Validar payload
const body = $input.first().json.body || $input.first().json;
const required = ['client_name', 'contact_email', 'plan', 'mrr_usd', 'source_lead_id'];
for (const f of required) {
  if (body[f] === undefined || body[f] === null || body[f] === '') {
    throw new Error(`Missing required field: ${f}`);
  }
}
const mrr = parseFloat(body.mrr_usd);
if (isNaN(mrr) || mrr <= 0) throw new Error('Invalid mrr_usd');

// Idempotency key: source_lead_id + plan (un lead solo se convierte una vez por plan)
const idempotency_key = body.idempotency_key || `onboard-${body.source_lead_id}-${body.plan}`;

let whatsapp = (body.whatsapp || '').replace(/\D/g, '');
if (whatsapp && whatsapp.length === 10) whatsapp = '57' + whatsapp;
if (whatsapp && !/^\d{11,15}$/.test(whatsapp)) whatsapp = null;

return [{
  json: {
    client_name: String(body.client_name).trim(),
    company: body.company || body.client_name,
    contact_email: String(body.contact_email).toLowerCase().trim(),
    whatsapp: whatsapp,
    plan: body.plan,
    mrr_usd: mrr,
    source_lead_id: body.source_lead_id,
    contract_start_date: body.contract_start_date || new Date().toISOString(),
    idempotency_key,
    stage: 'active',
    health_score: 100,
    churn_risk: false,
    created_at: new Date().toISOString()
  }
}];

